import React, { Component } from 'react'

class SectionJumbotron extends Component {
    render() {
        return (
        <section id="jumbotron">
            <div className="p-5 text-center bg-image">
                <div className="mask">
                    <div className="d-flex justify-content-center align-items-center h-100">
                        <div className="text-white">
                            <h2 className="display-4 mb-4">Tu parli italiano?</h2>
                            <h4 className="display-6 mb-5">Lorem Ipsum is simply dummy text.</h4>
                            <a className="custom-btn-success" href="#!">Contact</a>
                        </div>
                    </div>
                </div>
            </div>
        </section>
        )
    }
}

export default SectionJumbotron;