import React, { Component } from 'react'
import MatchingContext from '../../contexts/MatchingContext';
import ModelMatching from '../models/ModelMatching'

class MatchingExercises extends Component {

    static contextType = MatchingContext;

    state = {
        matchingExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9">

                        <div className="tab-content">

                            {/* aggettivi-1 */}
                            <div className="tab-pane fade show active" id="aggettivi-1">
                                <ModelMatching db={this.state.matchingExercises.aggettivi1} />
                            </div>

                            {/* aggettivi-2 */}
                            <div className="tab-pane fade" id="aggettivi-2">
                                <ModelMatching db={this.state.matchingExercises.aggettivi2} />
                            </div>

                            {/* aggettivi-3 */}
                            <div className="tab-pane fade" id="aggettivi-3">
                                <ModelMatching db={this.state.matchingExercises.aggettivi3} />
                            </div>

                            {/* aggettivi-4 */}
                            <div className="tab-pane fade" id="aggettivi-4">
                                <ModelMatching db={this.state.matchingExercises.aggettivi4} />
                            </div>

                            {/* countries-and-languages */}
                            <div className="tab-pane fade" id="countries-and-languages">
                                <ModelMatching db={this.state.matchingExercises.countriesAndLanguages} />
                            </div>

                            {/* ricerche-e-offerte */}
                            <div className="tab-pane fade" id="ricerche-e-offerte">
                                <ModelMatching db={this.state.matchingExercises.ricercheEOfferte} />
                            </div>

                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>CATEGORIES</h2>
                            <hr />
                            {/* aggettivi-1 */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#aggettivi-1">{this.state.matchingExercises.aggettivi1.title}</a>

                            {/* aggettivi-2 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#aggettivi-2">{this.state.matchingExercises.aggettivi2.title}</a>

                            {/* aggettivi-3 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#aggettivi-3">{this.state.matchingExercises.aggettivi3.title}</a>

                            {/* aggettivi-4 */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#aggettivi-4">{this.state.matchingExercises.aggettivi4.title}</a>

                            {/* countries-and-languages */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#countries-and-languages">{this.state.matchingExercises.countriesAndLanguages.title}</a>

                            {/* ricerche-e-offerte */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#ricerche-e-offerte">{this.state.matchingExercises.ricercheEOfferte.title}</a>
                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default MatchingExercises;