import React, { Component } from 'react'
import TestContext from '../../contexts/TestContext';
import ModelTest from '../models/ModelTest'

class TestExercises extends Component {

    static contextType = TestContext;

    state = {
        testExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9 mb-5">

                        <div className="tab-content">

                            {/* come-mangiano-i-ticinesi */}
                            <div className="tab-pane fade show active" id="come-mangiano-i-ticinesi">
                                <ModelTest db={this.state.testExercises.comeMangianoITicinesi} />
                            </div>

                            {/* gli-animali */}
                            <div className="tab-pane fade" id="gli-animali">
                                <ModelTest db={this.state.testExercises.gliAnimali} />
                            </div>

                            {/* un-po-di-curiosità-sulla-svizzera */}
                            <div className="tab-pane fade" id="un-po-di-curiosità-sulla-svizzera">
                                <ModelTest db={this.state.testExercises.unPoDiCuriositàSullaSvizzera} />
                            </div>
                        </div>   

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>CATEGORIES</h2>
                            <hr />
                            {/* come-mangiano-i-ticinesi */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#come-mangiano-i-ticinesi">{this.state.testExercises.comeMangianoITicinesi.title}</a>

                            {/* gli-animali */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#gli-animali">{this.state.testExercises.gliAnimali.title}</a>

                            {/* un-po-di-curiosità-sulla-svizzera */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#un-po-di-curiosità-sulla-svizzera">{this.state.testExercises.unPoDiCuriositàSullaSvizzera.title}</a>
                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default TestExercises;