import React, { Component } from 'react'
import parse from 'html-react-parser';

class ModelTrueOrFalse extends Component {

    state = {
        id : this.props.db.id,
        title : this.props.db.title,
        html : this.props.db.html,
        tests : this.props.db.tests,
        isShowAnswer : false,
        score : 0
    }

    showAnswers = () => {
        this.setState({
          isShowAnswers : !this.state.isShowAnswers
        })
    }

    checkAnswers = () => {
        this.clearScore()
        this.state.tests.map((test, indexTest) => {
            return this.getRadioList(indexTest).forEach(radio => {
                if(radio.checked){
                    if(radio.value == test.correctAnswerIndex){
                        this.setState((state) => {                       
                            return {score: state.score + 1}
                        });
                    }
                }
            })
        })
    }

    getRadioList = (pIndexTest) => {
        return document.getElementsByName(`question${pIndexTest+1}`);
    }

    clearScore = () => {
        this.setState((state) => {                       
            return {score: 0}
        });
    }

    clearAnswer = () => {
        this.clearScore()
        this.state.tests.map((test, indexTest) => {
            return this.getRadioList(indexTest).forEach((radio, indexRadio) => {
                radio.checked = false
            })
        })
    }

    render() {
        return (
            <>
            <h2>{this.state.title}</h2>
            <hr />
        
            <div>
                {parse(this.state.html)}
            </div>

            <div className="overflow-auto">
                <h2 className="mt-5 mb-4 float-start">Questions?</h2>
                <h2 className="mt-5 mb-4 float-end">Scor : <span>{this.state.score}</span> / {this.state.tests.length}</h2>
            </div>
            <hr />

            <div>
                {this.state.tests.map((test, indexTest) => (
                    <div className="mb-4">
                        <p>{indexTest+1}. {test.question}</p>

                        {test.answerList.map((answer, indexAnswer) => (
                            <div>
                                <input class="form-check-input me-2 mb-2" type="radio" name={"question" + (indexTest+1)} value={indexAnswer} />
                                {answer}
                            </div>
                        ))}
                    </div>
                ))}
            </div>

            <div>
                <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>

                <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">
                    {
                    this.state.isShowAnswers ? "Hide Answers" : "Show Answers"
                    }
                </button>  

                <button onClick={this.clearAnswer} className="btn btn-primary float-end">Clear</button>
            </div>

            {
            this.state.isShowAnswers
                ? <div className="row mb-5"> 
                    <h2 className="mt-5">Answers</h2>
                    <hr />
                    {this.state.tests.map((test, indexTest) => (
                        <p>
                            <span>{indexTest + 1}. </span>
                            {test.answerList[test.correctAnswerIndex]}
                        </p>
                    ))}
                </div>
                : null
            }
            </>
        )
    }
}

export default ModelTrueOrFalse;