import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import VegetableContext from '../../contexts/VegetableContext';

class LearnVegetables extends Component {

  static contextType = VegetableContext;

  state = {
      vegetables : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.vegetables} isThereArticolo={true} category="New Vegetable" />
        )
    }
}

export default LearnVegetables;