import React, { Component } from 'react'
import OrderTheSentencesContext from '../../contexts/OrderTheSentencesContext';
import ModelOrderTheSentences from '../models/ModelOrderTheSentences'

class OrderTheSentencesExercises extends Component {

    static contextType = OrderTheSentencesContext;

    state = {
        orderTheSentencesExercises : this.context,
    }

    render() {
        return (
            <div className="container">
                <div className="row mt-5 mb-5">

                    <div className="col-md-9">

                        <div className="tab-content">

                            {/* la-storia-di-mia-nonna */}
                            <div className="tab-pane fade show active" id="la-storia-di-mia-nonna">
                                <ModelOrderTheSentences db={this.state.orderTheSentencesExercises.laStoriaDiMiaNonna} />
                            </div>

                            {/* la-storia-di-mia-mamma */}
                            <div className="tab-pane fade" id="la-storia-di-mia-mamma">
                                <ModelOrderTheSentences db={this.state.orderTheSentencesExercises.laStoriaDiMiaMamma} />
                            </div>

                            {/* la-storia-di-mia-sorella */}
                            <div className="tab-pane fade" id="la-storia-di-mia-sorella">
                                <ModelOrderTheSentences db={this.state.orderTheSentencesExercises.laStoriaDiMiaSorella} />
                            </div>

                            {/* la-storia-del-leone-e-dell-asino */}
                            <div className="tab-pane fade" id="la-storia-del-leone-e-dell-asino">
                                <ModelOrderTheSentences db={this.state.orderTheSentencesExercises.laStoriaDelLeoneEDellAsino} />
                            </div>

                            {/* la-storia-della-mia-maestra */}
                            <div className="tab-pane fade" id="la-storia-della-mia-maestra">
                                <ModelOrderTheSentences db={this.state.orderTheSentencesExercises.laStoriaDellaMiaMaestra} />
                            </div>

                        </div>

                    </div>

                    <div className="col-md-3">

                        <div className="list-group" id="list-tab">

                            <h2>CATEGORIES</h2>
                            <hr />
                            {/* la-storia-di-mia-nonna */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#la-storia-di-mia-nonna">{this.state.orderTheSentencesExercises.laStoriaDiMiaNonna.title}</a>

                            {/* la-storia-di-mia-mamma */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#la-storia-di-mia-mamma">{this.state.orderTheSentencesExercises.laStoriaDiMiaMamma.title}</a>

                            {/* la-storia-di-mia-sorella */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#la-storia-di-mia-sorella">{this.state.orderTheSentencesExercises.laStoriaDiMiaSorella.title}</a>

                            {/* la-storia-del-leone-e-dell-asino */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#la-storia-del-leone-e-dell-asino">{this.state.orderTheSentencesExercises.laStoriaDelLeoneEDellAsino.title}</a>

                            {/* la-storia-della-mia-maestra */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#la-storia-della-mia-maestra">{this.state.orderTheSentencesExercises.laStoriaDellaMiaMaestra.title}</a>

                        </div>

                    </div>

                </div>
            </div>
        )
    }
}

export default OrderTheSentencesExercises;