import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import ColorContext from '../../contexts/ColorContext';

class LearnColors extends Component {

  static contextType = ColorContext;

    state = {
        colors : this.context,
    }

    render() {
        return (
            <ModelLearnWords db={this.state.colors} isThereArticolo={true} category="New Color" />
        )
    }
}

export default LearnColors;