import React, { Component } from 'react';
import { Container, Draggable } from 'react-smooth-dnd';
import Swal from 'sweetalert2'

class ModelWordFindingWithSyllables extends Component {

    // state = {
    //     title : this.props.db.title,
    //     syllableList : this.props.db.syllableList
    // }

    state = {
        title : "La storia di mia nonna",
        syllableList : [
            {
                "id" : 1,
                "text" : "GIO",
            },
            {
                "id" : 3,
                "text" : "NO",
            },
            {
                "id" : 0,
                "text" : "FA",
            },
            {
                "id" : 2,
                "text" : "LI",
            }
        ],
        isShowAnswer : false,
    }

    showAnswers = () => {
        this.setState({
          isShowAnswers : !this.state.isShowAnswers
        })
    }

    showSwal = (pResult) => {
        if(pResult){
            Swal.fire({
                icon: 'success'
            })
        } else{
            Swal.fire({
                icon: 'error'
            })
        }
    }

    applyDrag = (arr, dragResult) => {
        const { removedIndex, addedIndex, payload } = dragResult;
        if (removedIndex === null && addedIndex === null) return arr;  

        const result = [...arr];
        let itemToAdd = payload;  
        
        if (removedIndex !== null) {
        itemToAdd = result.splice(removedIndex, 1)[0];
        }
    
        if (addedIndex !== null) {
        result.splice(addedIndex, 0, itemToAdd);
        }
    
        return result;
    };

    render() {
        return (
        <div className="container">
            <div className="row mt-5">
                <div className="col-md-9">

                    <h2>Componi le parole con le sillabe.</h2>
                    <hr />

                    <div id="">
                        <Container orientation="horizontal" onDrop={e => this.setState({ syllableList: this.applyDrag(this.state.syllableList, e) })}>
                            {this.state.syllableList.map((syllable, index) => {
                                return (
                                    <Draggable key={index}>
                                        {/* <div className="">{syllable.text}</div> */}
                                        <span id={syllable.id} class="badge bg-secondary me-4 p-4 fs-2">{syllable.text}</span>
                                    </Draggable>
                                );
                            })}
                        </Container>
                    </div>

                </div>

                <div className="col-md-3">

                </div>
            </div>
        </div>
        );
    }
}

export default ModelWordFindingWithSyllables;