import React, { Component } from 'react'
import Select from 'react-select';
import VerbContext from '../../contexts/VerbContext';
import TimeItems from './TimeItems'


class VerbConjugations extends Component {

    static contextType = VerbContext;

    state = {
        selectedOption : null,
        verbs : this.context,
        currentVerb : ""
    };

    handleChange = selectedOption => {
        this.setState({ selectedOption });
        this.state.currentVerb = this.state.verbs.find(verb => verb.id == selectedOption.id)

        // console.log(this.state.currentVerb)
        // console.log(`Option selected:`, selectedOption);
        // console.log(selectedOption.id)
    };

    render() {
        const verbs = this.state.verbs.map(verb => {
            return { id: verb.id, value: verb.italian, label: verb.italian }
        })

        return (
        <div className="container">
            <div className="row my-5">

                <div className="col-md-9">

                    <div className="row">

                        <div className="col-md-12 mb-5">
                            <Select
                                value={this.state.selectedOption}
                                onChange={this.handleChange}
                                options={verbs}
                            />
                        </div>

                        <TimeItems title="Indicativo Presente" time={this.state.currentVerb.indicativoPresente} />
                        <TimeItems title="Indicativo Passato Prossimo" time={this.state.currentVerb.indicativoPassatoProssimo} />
                        <TimeItems title="Indicativo Futuro Semplice" time={this.state.currentVerb.indicativoFuturoSemplice} />
                        <TimeItems title="Indicativo Imperfetto" time={this.state.currentVerb.indicativoImperfetto} />
                        <TimeItems title="Condizionale Presente" time={this.state.currentVerb.condizionalePresente} />
                        <TimeItems title="Condizionale Passato" time={this.state.currentVerb.condizionalePassato} />
                        <TimeItems title="Congiuntivo Presente" time={this.state.currentVerb.congiuntivoPresente} />
                        <TimeItems title="Congiuntivo Passato" time={this.state.currentVerb.congiuntivoPassato} />
                        <TimeItems title="Congiuntivo Imperfetto" time={this.state.currentVerb.congiuntivoImperfetto} />
                        <TimeItems title="Congiuntivo Trapassato" time={this.state.currentVerb.congiuntivoTrapassato} />


                    </div>
                
                </div>
         
                <div className="col-md-3 text-center">
                    <img src="/images/advertisement/advertisement-300x600.png" alt="..." />
                </div>
            
            </div>
        </div> 
        ) 
    }
}

export default VerbConjugations;