import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import OccupationContext from '../../contexts/OccupationContext';

class LearnOccupations extends Component {

  static contextType = OccupationContext;

  state = {
      occupations : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.occupations} isThereArticolo={true} category="New Occupation" />
        )
    }
}

export default LearnOccupations;