import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import AdjectiveContext from '../../contexts/AdjectiveContext';

class LearnAdjectives extends Component {

  static contextType = AdjectiveContext;

  state = {
      adjectives : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.adjectives} isThereArticolo={true} category="New Adjective" />
        )
    }
}

export default LearnAdjectives;