import React, { Component } from 'react'

import ArticoliDeterminativo from './ArticoliDeterminativo'
import ArticoliIndeterminativo from './ArticoliIndeterminativo'
import IndicativoPresente from './IndicativoPresente'
import VerbiRiflessiviPresente from './VerbiRiflessiviPresente'
import IndicativoPassatoProssimo from './IndicativoPassatoProssimo'
import IndicativoFuturoSemplice from './IndicativoFuturoSemplice'
import Preposizioni from './Preposizioni'
import ParticelleInterrogative from './ParticelleInterrogative'

class Grammar extends Component {
    render() {
        return (
            <div className="container">
                <div className="row mt-5">
                    <div className="col-md-3 mb-5">
                        <div className="list-group" id="list-tab">

                            {/* articolo determinativo */}
                            <a className="list-group-item list-group-item-action active" data-mdb-toggle="list" href="#articolo-determinativo">Articolo Determinativo</a>

                            {/* articolo indeterminativo */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#articolo-indeterminativo">Articolo Indeterminativo</a>

                            {/* particelle interrogative */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#particelle-interrogative">Particelle Interrogative</a>

                            {/* preposizioni */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#preposizioni">Preposizioni</a>

                            {/* indicativo presente */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#indicativo-presente">Indicativo Presente</a>

                            {/* verbi riflessivi presente*/}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#verbi-riflessivi-presente">Verbi Riflessivi Presente</a>

                            {/* indicativo passato prossimo */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#indicativo-passato-prossimo">Indicativo Passato Prossimo</a>

                            {/* indicativo futuro semplice */}
                            <a className="list-group-item list-group-item-action" data-mdb-toggle="list" href="#indicativo-futuro-semplice">Indicativo Futuro Semplice</a>

                        </div>
                    </div>

                    <div className="col-md-9">
                        <div className="tab-content">

                             {/* articolo determinativo */}
                            <div className="tab-pane fade show active" id="articolo-determinativo">
                                <ArticoliDeterminativo />
                            </div>

                            {/* articolo indeterminativo */}
                            <div className="tab-pane fade" id="articolo-indeterminativo">
                                <ArticoliIndeterminativo />
                            </div>

                            {/* particelle interrogative */}
                            <div className="tab-pane fade" id="particelle-interrogative">
                                <ParticelleInterrogative />
                            </div>

                            {/* preposizioni */}
                            <div className="tab-pane fade" id="preposizioni">
                                <Preposizioni />
                            </div>

                            {/* indicativo presente */}
                            <div className="tab-pane fade" id="indicativo-presente">
                                <IndicativoPresente />
                            </div>

                            {/* verbi riflessivi presente*/}
                            <div className="tab-pane fade" id="verbi-riflessivi-presente">
                                <VerbiRiflessiviPresente />
                            </div>
                            
                            {/* indicativo passato prossimo */}
                            <div className="tab-pane fade" id="indicativo-passato-prossimo">
                                <IndicativoPassatoProssimo />
                            </div>

                            {/* indicativo futuro semplice */}
                            <div className="tab-pane fade" id="indicativo-futuro-semplice">
                                <IndicativoFuturoSemplice />
                            </div>

                        </div>
                    </div>

                </div>
            </div>
        )
    }
}

export default Grammar;