import React from 'react'
import {
  BrowserRouter as Router,
  Switch,
  Route
} from "react-router-dom";

// Components
import Header from './components/layout/Header'
import Navbar from './components/layout/Navbar'
import Footer from './components/layout/Footer'
import LearnWords from './components/learn-words/LearnWords'
import Grammar from './components/grammar/Grammar'
import Home from './components/home/Home'
import Reading from './components/reading/Reading'
import VerbConjugations from './components/verb-conjugations/VerbConjugations'
import TrueOrFalseExercises from './components/exercises/TrueOrFalseExercises';
import MatchingExercises from './components/exercises/MatchingExercises';
import MatchingWithImageExercises from './components/exercises/MatchingWithImageExercises';
import FillTheBlankExercises from './components/exercises/FillTheBlankExercises';
import TestExercises from './components/exercises/TestExercises';
import OrderTheSentencesExercises from './components/exercises/OrderTheSentencesExercises';
import VerbConjugationsExercises from './components/exercises/VerbConjugationsExercises';

import ModelWordFindingWithSyllables from './components/models/ModelWordFindingWithSyllables';

class App extends React.Component {

  render() {

    return (    
        <Router>
            <Header />
            <Navbar />

            <Switch>
              <Route exact path="/">
                <Home />
              </Route>
              <Route path="/italian-grammar">
                <Grammar />
              </Route>
              <Route path="/italian-reading">
                <Reading />
              </Route>
              <Route path="/italian-verb-conjugations">
                <VerbConjugations />
              </Route>
              <Route path="/italian-learn-words">
                <LearnWords />
              </Route>
              <Route path="/italian-exercises-true-or-false">
                <TrueOrFalseExercises />
              </Route>        
              <Route path="/italian-exercises-matching">
                <MatchingExercises />
              </Route>    
              <Route path="/italian-exercises-matching-with-image">
                <MatchingWithImageExercises />
              </Route>     
              <Route path="/italian-exercises-fill-the-blank">
                <FillTheBlankExercises />
              </Route> 
              <Route path="/italian-exercises-test">
                <TestExercises />
              </Route>
              <Route path="/italian-exercises-order-the-sentences">
                <OrderTheSentencesExercises />
              </Route>
              <Route path="/italian-exercises-verb-conjugations">
                <VerbConjugationsExercises />
              </Route>

              <Route path="/italian-exercises-word-finding-with-syllables">
                <ModelWordFindingWithSyllables />
              </Route>
            </Switch>

            <Footer />
          </Router>
    );
  }
}

export default App;