import React, { Component } from 'react'

import VerbContext from '../../contexts/VerbContext';

import IndicativoFuturoSemplice from './verb-conjugations/IndicativoFuturoSemplice'
import IndicativoPassatoProssimo from './verb-conjugations/IndicativoPassatoProssimo'
import IndicativoPresente from './verb-conjugations/IndicativoPresente'
import IndicativoImperfetto from './verb-conjugations/IndicativoImperfetto'
import CondizionalePresente from './verb-conjugations/CondizionalePresente'
import CondizionalePassato from './verb-conjugations/CondizionalePassato'
import CongiuntivoPresente from './verb-conjugations/CongiuntivoPresente'
import CongiuntivoPassato from './verb-conjugations/CongiuntivoPassato'
import CongiuntivoImperfetto from './verb-conjugations/CongiuntivoImperfetto'
import CongiuntivoTrapassato from './verb-conjugations/CongiuntivoTrapassato'

class VerbConjugationsExercises extends Component {

    static contextType = VerbContext;

    state = {
        verbs : this.context,
        currentVerb : ""
    }

    componentDidMount(){
        this.getRandomVerb()
    }

    getRandomVerb = () => {
        const randomNumber = Math.floor(Math.random() * this.state.verbs.length);
        this.setState({
            currentVerb : this.state.verbs[randomNumber]
        })
    };

    getVerbById = (e) => {
        this.setState({
            currentVerb : this.state.verbs.find(item => item.id === e.target.id)
        })
    }

    render() {
        return (
        <div className="container">
            <div className="row pt-5">

                <div className="col-md-9">

                    <div className="overflow-auto">                           
                        <h2 className="text-center float-start">{this.state.currentVerb.italian} ({this.state.currentVerb.english})</h2>
                        <button onClick={this.getRandomVerb} className="btn btn-primary float-end">New Verb</button>
                        <hr className="verb-conjugations-hr" />
                    </div>
                    <div className="row">

                        <IndicativoPresente currentVerb={this.state.currentVerb} />
                        <IndicativoPassatoProssimo currentVerb={this.state.currentVerb} />
                        <IndicativoFuturoSemplice currentVerb={this.state.currentVerb} />
                        <IndicativoImperfetto currentVerb={this.state.currentVerb} />

                        <CondizionalePresente currentVerb={this.state.currentVerb}  />
                        <CondizionalePassato currentVerb={this.state.currentVerb}  />

                        <CongiuntivoPresente currentVerb={this.state.currentVerb}  />
                        <CongiuntivoPassato currentVerb={this.state.currentVerb}  />
                        <CongiuntivoImperfetto currentVerb={this.state.currentVerb}  />
                        <CongiuntivoTrapassato currentVerb={this.state.currentVerb}  />

                    </div>
                </div>
         
                <div className="col-md-3">
                <h2 className="text-center">ALL VERBS</h2>
                <hr />
                <div className="accordion" id="accordionExample">
                    <div className="accordion-item">
                        <h2 className="accordion-header" id="headingOne">
                            <button className="accordion-button" type="button" data-mdb-toggle="collapse"
                                data-mdb-target="#collapseOne" aria-expanded="true" aria-controls="collapseOne">
                            </button>
                        </h2>
                        <div id="collapseOne" className="accordion-collapse collapse show" aria-labelledby="headingOne"
                            data-mdb-parent="#accordionExample">
                            <div id="accordion-body" className="accordion-body row">

                                {this.state.verbs
                                .sort(function(a, b) {
                                    return a.italian.localeCompare(b.italian);
                                })
                                .map(verb => {
                                    return <div key={verb.id} className="col-md-6"><div><a onClick={this.getVerbById} id={verb.id} href="#!">{verb.italian}</a></div></div>;
                                })}
                                
                            </div>
                        </div>
                    </div>
                </div>
                </div>
            
            </div>
        </div> 
        ) 
    }
}

export default VerbConjugationsExercises;