import React, { Component } from 'react';
import { Container, Draggable } from 'react-smooth-dnd';
import parse from 'html-react-parser';
import Swal from 'sweetalert2'

class ModelOrderTheSentences extends Component {

    state = {
        id : this.props.db.id,
        title : this.props.db.title,
        description : this.props.db.description,
        sentences : this.props.db.sentences,
        answer : this.props.db.answer,
        isShowAnswer : false,
    }     

    showAnswers = () => {
        this.setState({
          isShowAnswers : !this.state.isShowAnswers
        })
    }

    checkAnswers = () => {
        let result = true;
        // const sentenceList = document.getElementsByClassName("alert");
        const sentenceList =  document.querySelectorAll(`#${this.state.id} .alert`);
        
        sentenceList.forEach((sentence, index) => {
            if(sentence.id != index){
                result = false;
            }
        });

        this.showSwal(result)
    }

    showSwal = (pResult) => {
        if(pResult){
            Swal.fire({
                icon: 'success'
            })
        } else{
            Swal.fire({
                icon: 'error'
            })
        }
    }

    applyDrag = (arr, dragResult) => {
        const { removedIndex, addedIndex, payload } = dragResult;
        if (removedIndex === null && addedIndex === null) return arr;  

        const result = [...arr];
        let itemToAdd = payload;  
        
        if (removedIndex !== null) {
        itemToAdd = result.splice(removedIndex, 1)[0];
        }
    
        if (addedIndex !== null) {
        result.splice(addedIndex, 0, itemToAdd);
        }
    
        return result;
    };

    render() {
        return (
            <>
            <h2>{this.state.description}</h2>
            <hr />

            <div id={this.state.id}>
                <Container onDrop={e => this.setState({ sentences: this.applyDrag(this.state.sentences, e) })}>
                    
                        {this.state.sentences.map((sentence, index) => {
                            return (
                                <Draggable key={index}>
                                    <div className="alert alert-dark" id={sentence.id}>
                                        {sentence.text}
                                    </div>
                                </Draggable>
                            );
                        })}
                    
                </Container>
            </div>

            <div className="row mb-5">
                <div className="col-md-12">      
                    <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
                    <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">
                        {
                        this.state.isShowAnswers ? "Hide Answers" : "Show Answers"
                        }
                    </button>                 
                </div>
            </div>

            {
            this.state.isShowAnswers
                ? <div className="row mb-5"> 
                    <h2 className="mt-5">Answer</h2>
                    <hr />
                    <p>{parse(this.state.answer)}</p>
                </div>
                : null
            }
            </>
        );
    }
}

export default ModelOrderTheSentences;