import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import BodyPartsContext from '../../contexts/BodyPartsContext';

class LearnBodyParts extends Component {

  static contextType = BodyPartsContext;

  state = {
      bodyParts : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.bodyParts} isThereArticolo={true} category="New Body Part" />
        )
    }
}

export default LearnBodyParts;