import React, { Component } from 'react'
import parse from 'html-react-parser';

class ModelTrueOrFalse extends Component {

    state = {
        id : this.props.db.id,
        title : this.props.db.title,
        html : this.props.db.html,
        asks : this.props.db.asks,
        answers : this.props.db.answers,
        score : 0
    }

    showAnswers = () => {
        this.clearScore()
        this.clearBgColor()
        this.removeCheckedOfRadioButtons()

        this.state.asks.map((ask, index) => {
            return this.changeBgColorForTrueAnswers("ask" + (index+1) + "-" + this.state.id, index)
        })
    }

    checkAnswers = () => {
        this.clearScore()
        this.clearBgColor()

        this.state.asks.map((ask, index) => {
            return this.changeBgColorForCheckAnswers("ask" + (index+1) + "-" + this.state.id, index)
        })
    }

    changeBgColorForCheckAnswers = (pRadioButtonName, pAnswerIndex) => {
        document.getElementsByName(pRadioButtonName).forEach(item => {
            if(item.checked === true){
                if(item.value === this.state.answers[pAnswerIndex]){
                    item.parentElement.style.backgroundColor = "#BEEB9F"
                    this.setState((state) => {                       
                        return {score: state.score + 1}
                    });
                }else{
                    item.parentElement.style.backgroundColor = "#D99197"
                }
            }
        })
    }

    changeBgColorForTrueAnswers = (pRadioButtonName, pAnswerIndex) => {
        let answer = this.state.answers[pAnswerIndex]
        let radioButtons = document.getElementsByName(pRadioButtonName)
        if(answer === "true"){
            radioButtons[0].parentElement.style.backgroundColor = "#BEEB9F"
        } else{
            radioButtons[1].parentElement.style.backgroundColor = "#BEEB9F"
        }
    }

    removeCheckedOfRadioButtons = () => {
        document.querySelectorAll("tbody .form-check-input").forEach(radioButton => {
            radioButton.checked = false
        })
    }

    clearBgColor = () => {
        document.querySelectorAll("tbody td").forEach(td => {
            td.style.backgroundColor = "white"
        })
    }

    clearScore = () => {
        this.setState((state) => {                       
            return {score: 0}
        });
    }

    clearAnswer = () => {
        this.removeCheckedOfRadioButtons()
        this.clearBgColor()
        this.clearScore()
    }

    render() {
        return (
            <>
            <h2>{this.state.title}</h2>
            <hr />
        
            <div className="true-or-false-text">
                {parse(this.state.html)}
            </div>

            <h2 className="mt-5 mb-4 float-start">Vero o Falso?</h2>
            <h2 className="mt-5 mb-4 float-end">Scor : <span>{this.state.score}</span> / {this.state.answers.length}</h2>

            <table className="table table-bordered table-hover table-sm">
                <thead>
                    <tr>
                        <th></th>
                        <th className="w-66 text-center">V</th>
                        <th className="w-66 text-center">F</th>
                    </tr>
                </thead>
                <tbody>

                    {this.state.asks.map((ask, index) => (
                        <tr id={index} key={index}>
                            <td>{index + 1}. {ask} </td>
                            <td><input class="form-check-input" type="radio" name={"ask" + (index + 1) + "-" + this.state.id} value="true" /></td>
                            <td><input class="form-check-input" type="radio" name={"ask" + (index + 1) + "-" + this.state.id} value="false" /></td>
                        </tr>
                    ))}

                </tbody>
            </table>
            <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
            <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">Show</button>
            <button onClick={this.clearAnswer} className="btn btn-primary float-end">Clear</button>
            </>
        )
    }
}

export default ModelTrueOrFalse;