import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import VerbContext from '../../contexts/VerbContext';

class LearnVerbs extends Component {

  static contextType = VerbContext;

    state = {
        verbs : this.context,
    }

    render() {
        return (
            <ModelLearnWords db={this.state.verbs} isThereArticolo={false} category="New Verb" />
        )
    }
}

export default LearnVerbs;