import React, { Component } from 'react'

class TimeItems extends Component {
    render() {

        console.log("hahahahan", this.props.time)

        return (
            <div className="col-md-4 text-center mb-5">
                <button className="btn btn-secondary btn-block mb-4">{this.props.title}</button>
                <div>

                    {
                        this.props.time == undefined 
                        ? <><p>---</p><p>---</p><p>---</p><p>---</p><p>---</p><p>---</p></>
                        : this.props.time.map(item => (
                            <p>{item}</p>
                        ))
                    }

                </div>
            </div>
        )
    }
}

export default TimeItems;