import React, { Component } from 'react'

class ModelLearnWords extends Component {

    state = {
        words : this.props.db,
        isThereArticolo : this.props.isThereArticolo,
        currentVerb : ""
    }

    componentDidMount(){
        this.getNewWord()
    }

    getNewWord = () => {
        const randomNumber = Math.floor(Math.random() * this.state.words.length);
        this.setState({
            currentVerb : this.state.words[randomNumber]
        })
    };

    render() {
        return (
        <div class="col-md-6 mb-5 learn-words-container">

            <div class="card text-center">
                <div class="row">
                  <div class="col-md-4 img-container">
                    <img src={this.state.currentVerb.image} alt="..." class="img-fluid learn-words-img" />
                  </div>
                  <div class="col-md-8">
                    <div class="card-body">

                      {
                      this.state.isThereArticolo
                      ?
                      <h5 class="card-title">{this.state.currentVerb.italianSingular} ___ {this.state.currentVerb.italianPlural}</h5>
                      :                      
                      <h5 class="card-title">{this.state.currentVerb.italian}</h5>
                      }
                      
                      <hr />
                      <h5 class="card-title">{this.state.currentVerb.english}</h5>
                      <hr />
                      <h5 class="card-title">{this.state.currentVerb.turkish}</h5>
                    </div>
                  </div>
                </div>
                <button onClick={this.getNewWord} type="button" class="btn btn-primary">{this.props.category}</button>
            </div> 

        </div>
        )
    }
}

export default ModelLearnWords;