import React, { Component } from 'react'
import ModelLearnWords from '../models/ModelLearnWords'

import ClothesContext from '../../contexts/ClothesContext';

class LearnClothes extends Component {

  static contextType = ClothesContext;

  state = {
      clothes : this.context,
  }

    render() {
        return (
            <ModelLearnWords db={this.state.clothes} isThereArticolo={true} category="New Clothes" />
        )
    }
}

export default LearnClothes;