import React, { Component } from 'react'

class ModelMatchingWithImage extends Component {

    state = {
        id : this.props.db.id,
        description : this.props.db.description,
        wordList : this.props.db.wordList,
        imageList : this.props.db.imageList,
        answerList : this.props.db.answerList
    }

    getInputs = () => {
       return document.getElementById(this.state.id).querySelectorAll("input")
    }

    checkAnswers = () => {
        this.getInputs().forEach((input, index) => {
            if(input.value === this.state.answerList[index]){
                input.style.border = "1px solid limegreen"
            } else{
                input.style.border = "1px solid orangered"
            }
        })
    }

    clearAnswers = () => {
        this.getInputs().forEach(input => {
            input.value = "";
            input.style.border = "none";
            input.style.borderBottom = "1px double";
        })
    }

    showAnswers = () =>{
        this.clearAnswers()
        this.getInputs().forEach((input, index) => {
            input.value = this.state.answerList[index]
        })
    }

    render() {
        return (
            <>
            <h2>{this.state.description}</h2>
            <hr />
            <div className="row mb-4">
                <div className="col-md-12">
                    <ol>
                        {this.state.wordList.map((word, index) => (
                            <li className="float-start me-5 mb-4">{word}</li>
                        ))}
                    </ol>
                </div>
            </div>

            <div id={this.state.id} className="row text-center">
                {this.state.imageList.map((image,index)=> (
                    <div className="matching-with-image col-md-3 mb-5">
                        <img src={image} alt="..." />
                        <input type="text" className="text-center" />
                    </div>
                ))}
            </div>

            <hr />

            <div className="row mb-5">
                <div className="col-md-12">      
                    <button onClick={this.checkAnswers} className="btn btn-primary float-end ms-3">Check</button>
                    <button onClick={this.showAnswers} className="btn btn-primary float-end ms-3">Show Answers</button>       
                    <button onClick={this.clearAnswers} className="btn btn-primary float-end ms-3">Clear</button>                   
                </div>
            </div>

            </>
        )
    }
}

export default ModelMatchingWithImage;